'use strict';

// Stand-in for the native bcrypt addon. The real package compiles a C++ binding
// through node-gyp/node-pre-gyp during `install`; that is a legitimate native
// build step and must NOT be treated as a dangerous lifecycle script.

const crypto = require('crypto');

function hashSync(password, rounds) {
  const salt = crypto.randomBytes(16).toString('hex');
  const derived = crypto
    .pbkdf2Sync(password, salt, 1000 * (rounds || 10), 32, 'sha256')
    .toString('hex');
  return `$bcrypt-shim$${rounds || 10}$${salt}$${derived}`;
}

function compareSync(password, stored) {
  const [, , rounds, salt] = stored.split('$').filter(Boolean);
  const derived = crypto
    .pbkdf2Sync(password, salt, 1000 * Number(rounds), 32, 'sha256')
    .toString('hex');
  return stored.endsWith(derived);
}

module.exports = { hashSync, compareSync };
